// failed request count by name
let start= $__timeFrom();
let end= $__timeTo();
let timeGrain= 5m;
let dataset=requests
    // additional filters can be applied here
    | where timestamp > start and timestamp < end
    | where client_Type != "Browser"
;// calculate failed request count for all requests
dataset
| summarize failedCount=sumif(itemCount, success == false) by bin(timestamp, timeGrain)
| extend ["request"]='Overall'
// render result in a chart
| render timechart

// top dependency failures
let start= $__timeFrom();
let end= $__timeTo();
let timeGrain=5m;
let dataset=dependencies
    // additional filters can be applied here
    | where timestamp > start and timestamp < end
    | where client_Type != "Browser"
    | where success == false
;// select a filtered set of dependencies and count them by dependency type
dataset// change 'type' on the below line to segment by a different property
| summarize _count=sum(itemCount) by type
| sort by _count desc

