// this query calculates request duration percentiles and count by name
let start= $__timeFrom();
let end= $__timeTo();
let timeGrain=5m;
let dataset=requests
// additional filters can be applied here
| where timestamp > start and timestamp < end
| where client_Type != "Browser"
;
// calculate duration percentiles and count for all requests (overall)
dataset
// change 'operation_Name' on the below line to segment by a different property
| summarize avg_duration=sum(itemCount * duration)/sum(itemCount)
| sort by avg_duration desc

// this query calculates request duration percentiles and count by name
let start= $__timeFrom();
let end= $__timeTo();
let timeGrain=5m;
let dataset=requests
// additional filters can be applied here
| where timestamp > start and timestamp < end
| where client_Type != "Browser"
;
// calculate duration percentiles and count for all requests (overall)
dataset
| summarize avg_duration=sum(itemCount * duration)/sum(itemCount), percentiles(duration, 50, 95, 99), count_=sum(itemCount)
| project operation_Name="Overall", avg_duration, percentile_duration_50, percentile_duration_95, percentile_duration_99, count_
| union(dataset
// change 'operation_Name' on the below line to segment by a different property
| summarize avg_duration=sum(itemCount * duration)/sum(itemCount), percentiles(duration, 50, 95, 99), count_=sum(itemCount) by operation_Name
| sort by avg_duration desc, count_ desc
)

